<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sorting Visualizer</title>
<style>
  :root {
    --bg: #0f1117;
    --panel: #181b24;
    --bar: #4f8cff;
    --bar-active: #ffb347;
    --bar-sorted: #3ddc84;
    --text: #e6e8ee;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 24px;
    gap: 20px;
  }
  h1 { font-size: 1.3rem; font-weight: 600; letter-spacing: 0.02em; }
  #bars {
    display: flex;
    align-items: flex-end;
    gap: 3px;
    height: 320px;
    width: min(90vw, 800px);
    background: var(--panel);
    border-radius: 10px;
    padding: 16px;
  }
  .bar {
    flex: 1;
    background: var(--bar);
    border-radius: 3px 3px 0 0;
    transition: height 0.08s linear, background 0.08s linear;
    min-width: 2px;
  }
  .bar.active { background: var(--bar-active); }
  .bar.done { background: var(--bar-sorted); }
  #controls { display: flex; gap: 12px; }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid #2a2f3d;
    border-radius: 8px;
    padding: 10px 22px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s;
  }
  button:hover { background: #222736; border-color: var(--bar); }
  button:disabled { opacity: 0.5; cursor: not-allowed; }
</style>
</head>
<body>
  <h1>Sorting Algorithm Visualizer — Bubble Sort</h1>
  <div id="bars"></div>
  <div id="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>

<script>
(function () {
  const N = 40;
  const barsEl = document.getElementById('bars');
  const sortBtn = document.getElementById('sort');
  const shuffleBtn = document.getElementById('shuffle');
  const resetBtn = document.getElementById('reset');

  let arr = [];
  let initial = [];
  let animTimer = null;

  // Bubble sort state
  let i = 0;          // current comparison index within the pass
  let end = 0;        // unsorted region is [0, end)
  let swappedInPass = false;
  let isSorted = false;
  let activePair = [-1, -1];

  function checkSorted(a) {
    for (let k = 1; k < a.length; k++) if (a[k - 1] > a[k]) return false;
    return true;
  }

  function resetSortState() {
    i = 0;
    end = arr.length;
    swappedInPass = false;
    isSorted = checkSorted(arr);
    activePair = [-1, -1];
  }

  function render() {
    const max = Math.max(1, ...arr.map(v => Math.abs(v)));
    barsEl.innerHTML = '';
    for (let k = 0; k < arr.length; k++) {
      const bar = document.createElement('div');
      bar.className = 'bar';
      if (isSorted) bar.classList.add('done');
      else if (k === activePair[0] || k === activePair[1]) bar.classList.add('active');
      const h = Math.max(2, (Math.abs(arr[k]) / max) * 100);
      bar.style.height = h + '%';
      bar.title = String(arr[k]);
      barsEl.appendChild(bar);
    }
  }

  function sortStep() {
    if (isSorted) { activePair = [-1, -1]; render(); return true; }

    if (i >= end - 1) {
      // end of a pass
      if (!swappedInPass) {
        isSorted = true;
        activePair = [-1, -1];
        render();
        return true;
      }
      end--;
      i = 0;
      swappedInPass = false;
      if (end <= 1) {
        isSorted = true;
        activePair = [-1, -1];
        render();
        return true;
      }
    }

    activePair = [i, i + 1];
    if (arr[i] > arr[i + 1]) {
      const t = arr[i];
      arr[i] = arr[i + 1];
      arr[i + 1] = t;
      swappedInPass = true;
    }
    i++;
    render();

    if (checkSorted(arr) && i >= end - 1 && !swappedInPass || (isSorted = checkSorted(arr) && end <= 1)) {
      // fallthrough handled next call; keep simple
    }
    // Cheap early finish: if array is sorted and we just finished a pass with no swaps, next call reports true.
    return false;
  }

  function stopAnimation() {
    if (animTimer !== null) {
      clearInterval(animTimer);
      animTimer = null;
      sortBtn.disabled = false;
    }
  }

  function animateSort() {
    stopAnimation();
    sortBtn.disabled = true;
    animTimer = setInterval(() => {
      const done = sortStep();
      if (done) stopAnimation();
    }, 12);
  }

  function randomArray(n) {
    const a = [];
    for (let k = 0; k < n; k++) a.push(Math.floor(Math.random() * 195) + 5);
    return a;
  }

  function setArray(a) {
    stopAnimation();
    arr = a.map(Number);
    initial = arr.slice();
    resetSortState();
    render();
  }

  function shuffle() {
    stopAnimation();
    for (let k = arr.length - 1; k > 0; k--) {
      const j = Math.floor(Math.random() * (k + 1));
      const t = arr[k]; arr[k] = arr[j]; arr[j] = t;
    }
    resetSortState();
    render();
  }

  function reset() {
    stopAnimation();
    arr = initial.slice();
    resetSortState();
    render();
  }

  sortBtn.addEventListener('click', animateSort);
  shuffleBtn.addEventListener('click', shuffle);
  resetBtn.addEventListener('click', reset);

  window.viz = {
    array: () => arr.slice(),
    setArray: (a) => setArray(a),
    sortStep: () => sortStep(),
    sorted: () => checkSorted(arr),
  };

  setArray(randomArray(N));
})();
</script>
</body>
</html>
